from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Helper to join list items with commas and "and"
    def join_items(items):
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    # Group triples by subject
    subjects = {}
    for t in triples:
        subjects.setdefault(t.subject, []).append(t)

    sentences = []

    for subj, triples_list in subjects.items():
        # Containers for aggregated information
        genre = None
        instruments = []
        occupations = []
        backgrounds = []
        associated = []
        record_labels = []
        start_year = None
        end_year = None
        birth_info = []
        death_info = []
        origin = None

        # First pass: collect direct properties of the subject
        for t in triples_list:
            p, o = t.predicate, t.object
            if p == "genre":
                # allow multiple genres
                if isinstance(genre, list):
                    genre.append(o)
                else:
                    genre = [o] if genre is None else [genre, o]
            elif p == "instrument":
                instruments.append(o)
            elif p == "occupation":
                occupations.append(o)
            elif p == "background":
                backgrounds.append(o)
            elif p == "associatedBand/associatedMusicalArtist":
                associated.append(o)
            elif p == "recordLabel":
                record_labels.append(o)
            elif p == "activeYearsStartYear":
                start_year = o
            elif p == "activeYearsEndYear":
                end_year = o
            elif p in ("birthDate", "birthYear", "birthPlace"):
                birth_info.append(o)
            elif p in ("deathDate", "deathPlace"):
                death_info.append(o)
            elif p == "origin":
                origin = o

        # Build genre phrase with related genre triples (stylisticOrigin, derivative, musicFusionGenre, musicSubgenre)
        genre_phrase = ""
        if genre:
            genre_clauses = []
            for g in genre:
                # base name
                base = f"{g} music"
                # look for extra info about this genre
                extra = []
                for gt in subjects.get(g, []):
                    if gt.predicate == "stylisticOrigin":
                        extra.append(f"with stylistic origins in {gt.object}")
                    elif gt.predicate == "derivative":
                        extra.append(f"derived from {gt.object}")
                    elif gt.predicate == "musicFusionGenre":
                        extra.append(f"fused with {gt.object}")
                    elif gt.predicate == "musicSubgenre":
                        extra.append(f"subgenre {gt.object}")
                if extra:
                    clause = f"{base} ({', '.join(extra)})"
                else:
                    clause = base
                genre_clauses.append(clause)
            genre_phrase = join_items(genre_clauses)

        parts = []

        if genre:
            parts.append(f"is a {genre} musician")
        if instruments:
            parts.append(f"plays {join_items(instruments)}")
        if occupations:
            parts.append(f"works as {join_items(occupations)}")
        if backgrounds:
            parts.append(f"has a background as {join_items(backgrounds)}")
        if associated:
            parts.append(f"is associated with {join_items(associated)}")
        if record_labels:
            parts.append(f"is signed to {join_items(record_labels)}")
        if start_year:
            parts.append(f"started their career in {start_year}")
        if end_year:
            parts.append(f"ended their career in {end_year}")
        if origin:
            parts.append(f"originates from {origin}")
        if birth_info:
            parts.append(f"was born in {join_items(birth_info)}")
        if death_info:
            parts.append(f"died in {join_items(death_info)}")

        # Build sentence for this subject
        if parts:
            sentence = f"{subj} " + ", ".join(parts) + "."
        else:
            # Fallback: simple concatenation of triples
            simple_parts = [f"{t.predicate} {t.object}" for t in triples_list]
            sentence = f"{subj} " + ", ".join(simple_parts) + "."
        sentences.append(sentence)

    # Combine sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END

